/**
 * Coerces a raw string value to the specified type.
 * Returns { value, error } — either a coerced value or a descriptive error string.
 *
 * @param {string} raw
 * @param {string} type
 * @returns {{ value: any, error: string|null }}
 */
export function coerce(raw, type) {
  if (raw === undefined || raw === null) {
    return { value: undefined, error: null };
  }

  switch (type) {
    case "string":
      return { value: String(raw), error: null };

    case "number": {
      const n = Number(raw);
      if (isNaN(n)) {
        return { value: undefined, error: `must be a number (received "${raw}")` };
      }
      return { value: n, error: null };
    }

    case "boolean": {
      const lower = String(raw).toLowerCase().trim();
      if (["true", "1", "yes", "on"].includes(lower)) return { value: true, error: null };
      if (["false", "0", "no", "off"].includes(lower)) return { value: false, error: null };
      return { value: undefined, error: `must be a boolean (received "${raw}")` };
    }

    case "url": {
      try {
        new URL(raw);
        return { value: raw, error: null };
      } catch {
        return { value: undefined, error: `must be a valid URL (received "${raw}")` };
      }
    }

    case "email": {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(raw)) {
        return { value: undefined, error: `must be a valid email address (received "${raw}")` };
      }
      return { value: raw, error: null };
    }

    case "json": {
      try {
        return { value: JSON.parse(raw), error: null };
      } catch {
        return { value: undefined, error: `must be valid JSON (received "${raw}")` };
      }
    }

    default:
      return { value: raw, error: null };
  }
}
